class Solution:
    def minimumCoins(self, prices):
        n = len(prices)
        dp = [0] + [float('inf')] * n
        for i in range(1, n + 1):
            best = float('inf')
            for j in range(i):
                if 2 * j + 1 >= i - 1:
                    cand = dp[j] + prices[j]
                    if cand < best:
                        best = cand
            dp[i] = best
        return dp[n]

