var minimumCoins = function(prices) {
    const n = prices.length;
    const dp = new Array(n + 1).fill(Infinity);
    dp[0] = 0;
    for (let i = 1; i <= n; i++) {
        let best = Infinity;
        for (let j = 0; j < i; j++) {
            if (2 * j + 1 >= i - 1) {
                const cand = dp[j] + prices[j];
                if (cand < best) best = cand;
            }
        }
        dp[i] = best;
    }
    return dp[n];
};
